<script setup>
import { reactive, ref, watch } from 'vue';
import { Head, Link } from '@inertiajs/vue3';
import axios from 'axios';
import AppLayout from '@/Layouts/AppLayout.vue';
import Swal from 'sweetalert2';

const props=defineProps({projekt:Object,courses:Array,participants:Array});
const courseItems=ref(JSON.parse(JSON.stringify(props.courses||[])));
const form=reactive({title:'',description:'',status:'draft',starts_at:'',ends_at:'',capacity:'',self_enrollment:false});
const lessonForms=reactive({});
const enrollmentSelections=reactive({});
const materialForms=reactive({});
const assignmentForms=reactive({});
const quizForms=reactive({});
const questionForms=reactive({});
const sessionForms=reactive({});
const materialForm=(id)=>materialForms[id]||(materialForms[id]={title:'',file:null,published:false,sort_order:0,lesson_id:null});
const assignmentForm=(id)=>assignmentForms[id]||(assignmentForms[id]={title:'',instructions:'',due_at:'',max_points:'',allow_text:true,allow_file:true,published:false,sort_order:0,lesson_id:null});
const lessonForm=(id)=>lessonForms[id]||(lessonForms[id]={title:'',content:'',sort_order:courseItems.value.find(c=>c.id===id)?.lessons?.length||0,published:false});
const createCourse=async()=>{const r=await axios.post(route('projekt.courses.store',props.projekt.id),form);courseItems.value.unshift(r.data.course);Object.assign(form,{title:'',description:'',status:'draft',starts_at:'',ends_at:'',capacity:'',self_enrollment:false});};
const saveCourse=async(course)=>{const r=await axios.put(route('projekt.courses.update',course.id),{title:course.title,description:course.description||null,status:course.status,starts_at:course.starts_at?.slice(0,10)||null,ends_at:course.ends_at?.slice(0,10)||null,capacity:course.capacity||null,self_enrollment:Boolean(course.self_enrollment)});Object.assign(course,r.data.course);Swal.fire('Gespeichert',r.data.message,'success');};
const addLesson=async(course)=>{const lf=lessonForm(course.id);const r=await axios.post(route('projekt.courses.lessons.store',course.id),lf);course.lessons=course.lessons||[];course.lessons.push(r.data.lesson);lessonForms[course.id]={title:'',content:'',sort_order:course.lessons.length,published:false};};
const saveLesson=async(lesson)=>{const r=await axios.put(route('projekt.courses.lessons.update',lesson.id),{title:lesson.title,content:lesson.content||null,sort_order:lesson.sort_order,published:Boolean(lesson.published)});Object.assign(lesson,r.data.lesson);};
const enroll=async(course)=>{const ids=enrollmentSelections[course.id]||[];if(!ids.length)return;const r=await axios.post(route('projekt.courses.enroll',course.id),{project_person_ids:ids});course.enrollments=r.data.enrollments;enrollmentSelections[course.id]=[];};
const uploadMaterial=async(course)=>{const f=materialForm(course.id);if(!f.file||!f.title)return;const data=new FormData();data.append('title',f.title);data.append('file',f.file);data.append('published',f.published?'1':'0');data.append('sort_order',f.sort_order||0);if(f.lesson_id)data.append('lesson_id',f.lesson_id);const r=await axios.post(route('projekt.courses.materials.store',course.id),data,{headers:{'Content-Type':'multipart/form-data'}});(course.materials||(course.materials=[])).push(r.data.material);materialForms[course.id]={title:'',file:null,published:false,sort_order:course.materials.length,lesson_id:null};};
const saveMaterial=async(material)=>{const r=await axios.put(route('projekt.courses.materials.update',material.id),{title:material.title,published:Boolean(material.published),sort_order:material.sort_order||0});Object.assign(material,r.data.material);};
const addAssignment=async(course)=>{const f=assignmentForm(course.id);const r=await axios.post(route('projekt.courses.assignments.store',course.id),{...f,due_at:f.due_at||null,max_points:f.max_points||null,lesson_id:f.lesson_id||null});(course.assignments||(course.assignments=[])).push(r.data.assignment);assignmentForms[course.id]={title:'',instructions:'',due_at:'',max_points:'',allow_text:true,allow_file:true,published:false,sort_order:course.assignments.length,lesson_id:null};};
const saveAssignment=async(assignment)=>{const r=await axios.put(route('projekt.courses.assignments.update',assignment.id),{title:assignment.title,instructions:assignment.instructions||null,due_at:assignment.due_at||null,max_points:assignment.max_points||null,allow_text:Boolean(assignment.allow_text),allow_file:Boolean(assignment.allow_file),published:Boolean(assignment.published),sort_order:assignment.sort_order||0,lesson_id:assignment.lesson_id||null});Object.assign(assignment,r.data.assignment);};
const reviewSubmission=async(submission,status)=>{const r=await axios.put(route('projekt.courses.submissions.review',submission.id),{status,score:submission.score||null,feedback:submission.feedback||''});Object.assign(submission,r.data.submission);};
const quizForm=(id)=>quizForms[id]||(quizForms[id]={title:'',description:'',passing_percent:60,max_attempts:3,published:false,sort_order:0,lesson_id:null});
const questionForm=(id)=>questionForms[id]||(questionForms[id]={question:'',type:'single',points:1,sort_order:0,options:[{label:'',is_correct:true},{label:'',is_correct:false}]});
const addQuiz=async(course)=>{const r=await axios.post(route('projekt.courses.quizzes.store',course.id),quizForm(course.id));(course.quizzes||(course.quizzes=[])).push(r.data.quiz);quizForms[course.id]={title:'',description:'',passing_percent:60,max_attempts:3,published:false,sort_order:course.quizzes.length,lesson_id:null};};
const saveQuiz=async(quiz)=>{const r=await axios.put(route('projekt.courses.quizzes.update',quiz.id),{title:quiz.title,description:quiz.description||null,passing_percent:quiz.passing_percent,max_attempts:quiz.max_attempts,published:Boolean(quiz.published),sort_order:quiz.sort_order||0,lesson_id:quiz.lesson_id||null});Object.assign(quiz,r.data.quiz);};
const addQuestion=async(quiz)=>{const form=questionForm(quiz.id);const r=await axios.post(route('projekt.courses.quizzes.questions.store',quiz.id),form);(quiz.questions||(quiz.questions=[])).push(r.data.question);questionForms[quiz.id]={question:'',type:'single',points:1,sort_order:quiz.questions.length,options:[{label:'',is_correct:true},{label:'',is_correct:false}]};};
const saveQuestion=async(question)=>{const r=await axios.put(route('projekt.courses.quizzes.questions.update',question.id),{question:question.question,type:question.type,points:question.points,sort_order:question.sort_order||0,options:question.options.map(o=>({label:o.label,is_correct:Boolean(o.is_correct)}))});Object.assign(question,r.data.question);};
const addOption=(question)=>question.options.push({label:'',is_correct:false});
const normalizeSingleChoice = (questions) => (questions || []).forEach((question) => { if (question.type !== 'single') return; const clicked = (question.options || []).find((option) => option.is_correct === null); if (clicked) (question.options || []).forEach((option) => { option.is_correct = option === clicked; }); });
watch(courseItems, (courses) => courses.forEach((course) => (course.quizzes || []).forEach((quiz) => normalizeSingleChoice(quiz.questions))), { deep: true });
watch(questionForms, (forms) => Object.values(forms).forEach((form) => normalizeSingleChoice([form])), { deep: true });
const sessionForm=(id)=>sessionForms[id]||(sessionForms[id]={title:'',description:'',starts_at:'',ends_at:'',mode:'presence',location:'',online_url:'',published:false});
const addSession=async(course)=>{const f=sessionForm(course.id);const r=await axios.post(route('projekt.courses.sessions.store',course.id),{...f,location:f.location||null,online_url:f.online_url||null,description:f.description||null});(course.sessions||(course.sessions=[])).push(r.data.session);sessionForms[course.id]={title:'',description:'',starts_at:'',ends_at:'',mode:'presence',location:'',online_url:'',published:false};};
const saveSession=async(session)=>{const r=await axios.put(route('projekt.courses.sessions.update',session.id),{title:session.title,description:session.description||null,starts_at:session.starts_at,ends_at:session.ends_at,mode:session.mode,location:session.location||null,online_url:session.online_url||null,published:Boolean(session.published)});Object.assign(session,r.data.session);};
const attendanceRow=(session,enrollment)=>{session.attendance=session.attendance||[];let row=session.attendance.find(item=>item.enrollment_id===enrollment.id);if(!row){row={enrollment_id:enrollment.id,status:'planned',attended_minutes:null,note:null};session.attendance.push(row);}return row;};
const saveSessionAttendance=async(course,session)=>{const attendance=(course.enrollments||[]).map(enrollment=>{const row=attendanceRow(session,enrollment);return{enrollment_id:enrollment.id,status:row.status,attended_minutes:row.attended_minutes||null,note:row.note||null};});const r=await axios.put(route('projekt.courses.sessions.attendance',session.id),{attendance});session.attendance=r.data.attendance;};
</script>

<template>
<Head :title="`Kurse ${projekt.name}`"/><AppLayout><template #header><div class="flex justify-between"><span>Kurse · {{ projekt.name }}</span><Link :href="route('projekt.show',projekt.id)" class="text-sm text-zbb">Zurück zum Projekt</Link></div></template>
<div class="space-y-6">
<form class="rounded-xl bg-white p-5 shadow" @submit.prevent="createCourse"><h2 class="font-semibold">Neuen Kurs anlegen</h2><div class="mt-3 grid gap-3 md:grid-cols-4"><input v-model="form.title" required placeholder="Kurstitel" class="rounded border-gray-300"/><select v-model="form.status" class="rounded border-gray-300"><option value="draft">Entwurf</option><option value="published">Veröffentlicht</option><option value="archived">Archiviert</option></select><input v-model="form.starts_at" type="date" class="rounded border-gray-300"/><input v-model="form.ends_at" type="date" class="rounded border-gray-300"/><input v-model="form.capacity" type="number" min="1" placeholder="Kapazität" class="rounded border-gray-300"/><label class="flex items-center gap-2"><input v-model="form.self_enrollment" type="checkbox"/>Selbstanmeldung</label></div><textarea v-model="form.description" class="mt-3 w-full rounded border-gray-300" placeholder="Beschreibung"></textarea><button class="mt-3 rounded bg-zbb px-4 py-2 text-white">Kurs anlegen</button></form>
<article v-for="course in courseItems" :key="course.id" class="rounded-xl bg-white p-5 shadow"><div class="grid gap-3 md:grid-cols-4"><input v-model="course.title" class="rounded border-gray-300 font-semibold"/><select v-model="course.status" class="rounded border-gray-300"><option value="draft">Entwurf</option><option value="published">Veröffentlicht</option><option value="archived">Archiviert</option></select><input v-model="course.capacity" type="number" min="1" placeholder="Kapazität" class="rounded border-gray-300"/><label class="flex items-center gap-2"><input v-model="course.self_enrollment" type="checkbox"/>Selbstanmeldung</label></div><textarea v-model="course.description" class="mt-3 w-full rounded border-gray-300"></textarea><button class="mt-2 rounded border px-3 py-2 text-sm" @click="saveCourse(course)">Kurs speichern</button>
<div class="mt-5 grid gap-5 lg:grid-cols-2"><section><h3 class="font-semibold">Lektionen</h3><div v-for="lesson in course.lessons" :key="lesson.id" class="mt-2 rounded border p-3"><input v-model="lesson.title" class="w-full rounded border-gray-300 text-sm"/><textarea v-model="lesson.content" rows="3" class="mt-2 w-full rounded border-gray-300 text-sm"></textarea><div class="mt-2 flex gap-3"><input v-model.number="lesson.sort_order" type="number" class="w-20 rounded border-gray-300 text-sm"/><label><input v-model="lesson.published" type="checkbox"/> veröffentlicht</label><button class="text-sm text-zbb" @click="saveLesson(lesson)">Speichern</button></div></div><div class="mt-3 rounded border border-dashed p-3"><input v-model="lessonForm(course.id).title" placeholder="Neue Lektion" class="w-full rounded border-gray-300 text-sm"/><textarea v-model="lessonForm(course.id).content" class="mt-2 w-full rounded border-gray-300 text-sm"></textarea><label class="mt-2 block text-sm"><input v-model="lessonForm(course.id).published" type="checkbox"/> sofort veröffentlichen</label><button class="mt-2 rounded bg-zbb px-3 py-2 text-sm text-white" @click="addLesson(course)">Lektion anlegen</button></div></section>
<section><h3 class="font-semibold">Einschreibungen ({{ course.enrollments?.length||0 }})</h3><div class="mt-2 max-h-56 space-y-1 overflow-auto rounded border p-3"><label v-for="p in participants" :key="p.id" class="flex gap-2 text-sm"><input v-model="enrollmentSelections[course.id]" type="checkbox" :value="p.id"/>{{ p.teilnehmer?.nachname }}, {{ p.teilnehmer?.vorname }}</label></div><button class="mt-2 rounded bg-zbb px-3 py-2 text-sm text-white" @click="enroll(course)">Ausgewählte einschreiben</button><div class="mt-3 text-sm text-gray-500"><p v-for="e in course.enrollments" :key="e.id">{{ e.participation?.teilnehmer?.vorname }} {{ e.participation?.teilnehmer?.nachname }} · {{ e.status }}</p></div></section></div></article>
<article v-for="course in courseItems" :key="`content-${course.id}`" class="rounded-xl bg-white p-5 shadow"><h2 class="text-lg font-semibold">Lerninhalte · {{ course.title }}</h2><div class="mt-5 grid gap-6 lg:grid-cols-2"><section><h3 class="font-semibold">Materialien</h3><div v-for="material in course.materials" :key="material.id" class="mt-2 rounded border p-3"><input v-model="material.title" class="w-full rounded border-gray-300 text-sm"/><div class="mt-2 flex flex-wrap gap-3 text-sm"><label><input v-model="material.published" type="checkbox"/> veröffentlicht</label><input v-model.number="material.sort_order" type="number" class="w-20 rounded border-gray-300 text-sm"/><a :href="route('projekt.courses.materials.download',material.id)" class="text-zbb">Download</a><button class="text-zbb" @click="saveMaterial(material)">Speichern</button></div></div><div class="mt-3 rounded border border-dashed p-3"><input v-model="materialForm(course.id).title" placeholder="Materialtitel" class="w-full rounded border-gray-300 text-sm"/><input type="file" class="mt-2 w-full text-sm" @change="materialForm(course.id).file=$event.target.files[0]"/><label class="mt-2 block text-sm"><input v-model="materialForm(course.id).published" type="checkbox"/> sofort veröffentlichen</label><button class="mt-2 rounded bg-zbb px-3 py-2 text-sm text-white" @click="uploadMaterial(course)">Material hochladen</button></div></section><section><h3 class="font-semibold">Aufgaben und Abgaben</h3><div v-for="assignment in course.assignments" :key="assignment.id" class="mt-2 rounded border p-3"><input v-model="assignment.title" class="w-full rounded border-gray-300 text-sm"/><textarea v-model="assignment.instructions" rows="2" class="mt-2 w-full rounded border-gray-300 text-sm"></textarea><div class="mt-2 grid gap-2 sm:grid-cols-3"><input v-model="assignment.due_at" type="datetime-local" class="rounded border-gray-300 text-sm"/><input v-model="assignment.max_points" type="number" min="0" step="0.01" placeholder="Max. Punkte" class="rounded border-gray-300 text-sm"/><label class="text-sm"><input v-model="assignment.published" type="checkbox"/> veröffentlicht</label></div><button class="mt-2 text-sm text-zbb" @click="saveAssignment(assignment)">Aufgabe speichern</button><div v-for="submission in assignment.submissions" :key="submission.id" class="mt-3 rounded bg-gray-50 p-3 text-sm"><p class="font-semibold">{{ submission.enrollment?.participation?.teilnehmer?.vorname }} {{ submission.enrollment?.participation?.teilnehmer?.nachname }}</p><p v-if="submission.text_answer" class="mt-1 whitespace-pre-wrap">{{ submission.text_answer }}</p><a v-if="submission.path" :href="route('projekt.courses.submissions.download',submission.id)" class="text-zbb">Datei herunterladen</a><div class="mt-2 grid gap-2 sm:grid-cols-2"><input v-model="submission.score" type="number" min="0" step="0.01" placeholder="Punkte" class="rounded border-gray-300 text-sm"/><input v-model="submission.feedback" placeholder="Feedback" class="rounded border-gray-300 text-sm"/></div><div class="mt-2 flex gap-2"><button class="rounded bg-green-600 px-3 py-1 text-xs text-white" @click="reviewSubmission(submission,'reviewed')">Bewerten</button><button class="rounded bg-amber-600 px-3 py-1 text-xs text-white" @click="reviewSubmission(submission,'revision_requested')">Überarbeitung</button></div></div></div><div class="mt-3 rounded border border-dashed p-3"><input v-model="assignmentForm(course.id).title" placeholder="Neue Aufgabe" class="w-full rounded border-gray-300 text-sm"/><textarea v-model="assignmentForm(course.id).instructions" placeholder="Arbeitsauftrag" class="mt-2 w-full rounded border-gray-300 text-sm"></textarea><div class="mt-2 grid gap-2 sm:grid-cols-2"><input v-model="assignmentForm(course.id).due_at" type="datetime-local" class="rounded border-gray-300 text-sm"/><input v-model="assignmentForm(course.id).max_points" type="number" min="0" step="0.01" placeholder="Max. Punkte" class="rounded border-gray-300 text-sm"/></div><div class="mt-2 flex gap-3 text-sm"><label><input v-model="assignmentForm(course.id).allow_text" type="checkbox"/> Text</label><label><input v-model="assignmentForm(course.id).allow_file" type="checkbox"/> Datei</label><label><input v-model="assignmentForm(course.id).published" type="checkbox"/> veröffentlichen</label></div><button class="mt-2 rounded bg-zbb px-3 py-2 text-sm text-white" @click="addAssignment(course)">Aufgabe anlegen</button></div></section></div></article>
<article v-for="course in courseItems" :key="`quiz-${course.id}`" class="rounded-xl bg-white p-5 shadow"><h2 class="text-lg font-semibold">Quiz · {{ course.title }}</h2><div v-for="quiz in course.quizzes" :key="quiz.id" class="mt-4 rounded-xl border p-4"><div class="grid gap-2 md:grid-cols-4"><input v-model="quiz.title" class="rounded border-gray-300"/><input v-model.number="quiz.passing_percent" type="number" min="0" max="100" placeholder="Bestehen %" class="rounded border-gray-300"/><input v-model.number="quiz.max_attempts" type="number" min="1" placeholder="Versuche" class="rounded border-gray-300"/><label><input v-model="quiz.published" type="checkbox"/> veröffentlicht</label></div><textarea v-model="quiz.description" class="mt-2 w-full rounded border-gray-300"></textarea><button class="mt-2 text-sm text-zbb" @click="saveQuiz(quiz)">Quiz speichern</button><div v-for="question in quiz.questions" :key="question.id" class="mt-3 rounded bg-gray-50 p-3"><textarea v-model="question.question" class="w-full rounded border-gray-300 text-sm"></textarea><div class="mt-2 flex gap-2"><select v-model="question.type" class="rounded border-gray-300 text-sm"><option value="single">Einzelauswahl</option><option value="multiple">Mehrfachauswahl</option></select><input v-model="question.points" type="number" min="0.01" step="0.01" class="w-24 rounded border-gray-300 text-sm"/></div><label v-for="option in question.options" :key="option.id" class="mt-2 flex gap-2"><input v-model="option.is_correct" :type="question.type==='single'?'radio':'checkbox'" :name="`correct-${question.id}`"/><input v-model="option.label" class="flex-1 rounded border-gray-300 text-sm"/></label><button class="mt-2 text-sm text-zbb" @click="addOption(question)">Antwort ergänzen</button><button class="ml-3 text-sm text-zbb" @click="saveQuestion(question)">Frage speichern</button></div><div class="mt-3 rounded border border-dashed p-3"><textarea v-model="questionForm(quiz.id).question" placeholder="Neue Frage" class="w-full rounded border-gray-300 text-sm"></textarea><div class="mt-2 flex gap-2"><select v-model="questionForm(quiz.id).type" class="rounded border-gray-300 text-sm"><option value="single">Einzelauswahl</option><option value="multiple">Mehrfachauswahl</option></select><input v-model="questionForm(quiz.id).points" type="number" min="0.01" step="0.01" class="w-24 rounded border-gray-300 text-sm"/></div><label v-for="(option,index) in questionForm(quiz.id).options" :key="index" class="mt-2 flex gap-2"><input v-model="option.is_correct" :type="questionForm(quiz.id).type==='single'?'radio':'checkbox'" :name="`new-correct-${quiz.id}`"/><input v-model="option.label" placeholder="Antwort" class="flex-1 rounded border-gray-300 text-sm"/></label><button class="mt-2 text-sm text-zbb" @click="addOption(questionForm(quiz.id))">Antwort ergänzen</button><button class="ml-3 rounded bg-zbb px-3 py-2 text-sm text-white" @click="addQuestion(quiz)">Frage anlegen</button></div><div v-if="quiz.attempts?.length" class="mt-3 text-sm"><p v-for="attempt in quiz.attempts" :key="attempt.id">{{ attempt.enrollment?.participation?.teilnehmer?.vorname }} {{ attempt.enrollment?.participation?.teilnehmer?.nachname }} · {{ attempt.percentage }} % · {{ attempt.passed?'bestanden':'nicht bestanden' }}</p></div></div><div class="mt-4 rounded border border-dashed p-4"><input v-model="quizForm(course.id).title" placeholder="Neues Quiz" class="w-full rounded border-gray-300"/><textarea v-model="quizForm(course.id).description" placeholder="Beschreibung" class="mt-2 w-full rounded border-gray-300"></textarea><div class="mt-2 flex flex-wrap gap-3"><label>Bestehen % <input v-model.number="quizForm(course.id).passing_percent" type="number" min="0" max="100" class="w-20 rounded border-gray-300"/></label><label>Versuche <input v-model.number="quizForm(course.id).max_attempts" type="number" min="1" class="w-20 rounded border-gray-300"/></label><label><input v-model="quizForm(course.id).published" type="checkbox"/> veröffentlichen</label></div><button class="mt-3 rounded bg-zbb px-3 py-2 text-white" @click="addQuiz(course)">Quiz anlegen</button></div></article>
<article v-for="course in courseItems" :key="`sessions-${course.id}`" class="rounded-xl bg-white p-5 shadow"><h2 class="text-lg font-semibold">Kurstermine · {{ course.title }}</h2><div v-for="session in course.sessions" :key="session.id" class="mt-4 rounded-xl border p-4"><div class="grid gap-2 md:grid-cols-3"><input v-model="session.title" class="rounded border-gray-300"/><input v-model="session.starts_at" type="datetime-local" class="rounded border-gray-300"/><input v-model="session.ends_at" type="datetime-local" class="rounded border-gray-300"/><select v-model="session.mode" class="rounded border-gray-300"><option value="presence">Präsenz</option><option value="online">Online</option><option value="hybrid">Hybrid</option></select><input v-model="session.location" placeholder="Ort / Raum" class="rounded border-gray-300"/><input v-model="session.online_url" placeholder="Online-Link" class="rounded border-gray-300"/><label><input v-model="session.published" type="checkbox"/> veröffentlicht</label></div><textarea v-model="session.description" class="mt-2 w-full rounded border-gray-300"></textarea><button class="mt-2 text-sm text-zbb" @click="saveSession(session)">Termin speichern</button><div v-if="course.enrollments?.length" class="mt-4 overflow-x-auto"><table class="w-full text-sm"><thead><tr class="text-left"><th>Teilnehmer</th><th>Status</th><th>Minuten</th><th>Notiz</th></tr></thead><tbody><tr v-for="enrollment in course.enrollments" :key="enrollment.id"><td>{{ enrollment.participation?.teilnehmer?.vorname }} {{ enrollment.participation?.teilnehmer?.nachname }}</td><td><select v-model="attendanceRow(session,enrollment).status" class="rounded border-gray-300 text-sm"><option value="planned">Geplant</option><option value="attended">Teilgenommen</option><option value="absent">Abwesend</option><option value="excused">Entschuldigt</option></select></td><td><input v-model="attendanceRow(session,enrollment).attended_minutes" type="number" min="0" class="w-24 rounded border-gray-300 text-sm"/></td><td><input v-model="attendanceRow(session,enrollment).note" class="rounded border-gray-300 text-sm"/></td></tr></tbody></table><button class="mt-3 rounded bg-green-700 px-3 py-2 text-sm text-white" @click="saveSessionAttendance(course,session)">Teilnahme speichern</button></div></div><div class="mt-4 rounded border border-dashed p-4"><h3 class="font-semibold">Neuer Kurstermin</h3><div class="mt-2 grid gap-2 md:grid-cols-3"><input v-model="sessionForm(course.id).title" placeholder="Titel" class="rounded border-gray-300"/><input v-model="sessionForm(course.id).starts_at" type="datetime-local" class="rounded border-gray-300"/><input v-model="sessionForm(course.id).ends_at" type="datetime-local" class="rounded border-gray-300"/><select v-model="sessionForm(course.id).mode" class="rounded border-gray-300"><option value="presence">Präsenz</option><option value="online">Online</option><option value="hybrid">Hybrid</option></select><input v-model="sessionForm(course.id).location" placeholder="Ort / Raum" class="rounded border-gray-300"/><input v-model="sessionForm(course.id).online_url" placeholder="Online-Link" class="rounded border-gray-300"/><label><input v-model="sessionForm(course.id).published" type="checkbox"/> veröffentlichen</label></div><textarea v-model="sessionForm(course.id).description" placeholder="Beschreibung" class="mt-2 w-full rounded border-gray-300"></textarea><button class="mt-3 rounded bg-zbb px-3 py-2 text-white" @click="addSession(course)">Termin anlegen</button></div></article>
</div></AppLayout>
</template>
